import React from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Divider,
  Box
} from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: ForecastItem[];
}

/**
 * Maps common weather conditions to emojis for visual representation.
 */
const getWeatherEmoji = (condition: string): string => {
  const lower = condition.toLowerCase();
  if (lower.includes('sun') || lower.includes('clear')) return '☀️';
  if (lower.includes('cloud')) return '☁️';
  if (lower.includes('rain') || lower.includes('drizzle')) return '🌧️';
  if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
  if (lower.includes('snow')) return '❄️';
  if (lower.includes('fog') || lower.includes('mist')) return '🌫️';
  return '⛅';
};

/**
 * WeatherCard - A theme-aware component for displaying weather information.
 */
export default function WeatherCard({
  city = 'Tokyo',
  temperature = 28,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 8,
  unit = 'C',
  forecast = []
}: Props) {
  const currentIcon = getWeatherEmoji(condition);

  return (
    <Card 
      padding={0} 
      shadow="md" 
      radius="xl"
      border={true}
      style={{ overflow: 'hidden', maxWidth: '400px' }}
    >
      <Stack gap={0}>
        {/* Main Content Area */}
        <Box padding={24}>
          <Stack gap={24}>
            {/* Header: City and Date */}
            <Stack direction="horizontal" justify="between" align="start">
              <Stack gap={4}>
                <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                  {city}
                </Heading>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {new Date().toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' })}
                </Text>
              </Stack>
              <Text size="3xl" aria-hidden="true" style={{ lineHeight: 1 }}>{currentIcon}</Text>
            </Stack>

            {/* Current Weather Display */}
            <Stack direction="horizontal" align="center" justify="between">
              <Stack gap={0}>
                <Text 
                  size="4xl" 
                  weight="bold" 
                  color="var(--ggui-color-primary-600, #0284c7)"
                >
                  {temperature}°{unit}
                </Text>
                <Text variant="bodyLarge" weight="medium">
                  {condition}
                </Text>
              </Stack>

              <Stack direction="horizontal" gap={16} align="center">
                <Stack align="center" gap={2}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                  <Text weight="semibold">{humidity}%</Text>
                </Stack>
                <Divider orientation="vertical" margin={4} color="var(--ggui-color-outline, #d4d4d8)" />
                <Stack align="center" gap={2}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
                  <Text weight="semibold">{windSpeed} {unit === 'C' ? 'km/h' : 'mph'}</Text>
                </Stack>
              </Stack>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* 5-Day Forecast Strip */}
        <Box 
          background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
          padding={20}
        >
          <Stack direction="horizontal" justify="between" align="center" gap={8} wrap={false}>
            {forecast.map((item, index) => (
              <Stack 
                key={`${item.day}-${index}`} 
                align="center" 
                gap={8}
                style={{ flex: 1 }}
              >
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day}
                </Text>
                <Text size="xl" aria-label={item.day}>{item.icon}</Text>
                <Stack direction="horizontal" gap={4} justify="center">
                  <Text variant="caption" weight="semibold">
                    {item.high}°
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.low}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

