  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Maps a weather condition string to an appropriate emoji for the current display.
 */
const getWeatherEmoji = (condition: string): string => {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('partly')) return '⛅';
  if (normalized.includes('cloud')) return '☁️';
  if (normalized.includes('rain') || normalized.includes('drizzle')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow') || normalized.includes('freeze')) return '❄️';
  if (normalized.includes('mist') || normalized.includes('fog')) return '🌫️';
  if (normalized.includes('wind')) return '💨';
  return '🌤️';
};

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast,
}: Props) {
  const currentEmoji = getWeatherEmoji(condition);

  return (
    <Card shadow="md" padding={24} radius="xl">
      <Stack direction="vertical" gap={24}>
        {/* Header: City and Condition */}
