          <Text variant="bodyLarge" weight="medium">
            {condition}
          </Text>
        </Stack>

        {/* Hero: Large Temperature and Icon */}
        <Stack direction="horizontal" justify="center" align="center" gap={16}>
          <Text size="4xl">
            <span role="img" aria-label={condition}>
              {currentEmoji}
            </span>
          </Text>
          <Stack direction="horizontal" align="start" gap={2}>
            <Text size="4xl" weight="bold">
              {temperature}°
            </Text>
            <Text 
              size="xl" 
              weight="medium" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {unit}
            </Text>
          </Stack>
        </Stack>

        {/* Details: Humidity and Wind in a themed strip */}
        <Box 
          background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
          borderRadius="var(--ggui-shape-radius-lg, 12px)" 
          padding={16}
        >
          <Stack direction="horizontal" justify="around" align="center">
            <Stack direction="vertical" align="center" gap={4}>
              <Text 
                variant="caption" 
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <Text variant="bodyLarge" weight="semibold">
                {humidity}%
              </Text>
            </Stack>
            <Stack direction="vertical" align="center" gap={4}>
              <Text 
                variant="caption" 
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind
              </Text>
              <Text variant="bodyLarge" weight="semibold">
                {windSpeed} km/h
              </Text>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={0} />

        {/* Forecast: 5-day horizontal strip */}
        <Stack direction="horizontal" justify="between" align="center">
          {forecast.map((item, index) => (
            <Stack 
              key={`${item.day || index}-${index}`} 
              direction="vertical" 
              align="center" 
              gap={8}
            >
              <Text 
                variant="bodySmall" 
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {item.day}
              </Text>
              <Text size="xl">
                <span role="img" aria-label={item.day ? `Forecast for ${item.day}` : 'Forecast emoji'}>
                  {item.icon}
