        </Stack>

        {/* Main Temperature Display */}
        <Stack gap={8} align="center">
          <Text size="4xl" weight="bold">{temperature}°{unit}</Text>
          <Text variant="bodyLarge">{condition}</Text>
        </Stack>

        {/* Details Row */}
        <Stack direction="horizontal" justify="evenly" align="center" gap={16}>
          <Stack align="center" gap={4}>
            <Text variant="overline" color="var(--ggui-color-neutral-500, #6b7280)">Humidity</Text>
            <Text weight="medium">{humidity}%</Text>
          </Stack>
          <Divider orientation="vertical" />
          <Stack align="center" gap={4}>
            <Text variant="overline" color="var(--ggui-color-neutral-500, #6b7280)">Wind</Text>
            <Text weight="medium">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        {/* Forecast Strip */}
        <Box padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
          <Stack direction="horizontal" justify="between" align="center" gap={16}>
            {forecast.map((item, index) => (
              <Stack key={index} align="center" gap={4}>
                <Text variant="caption" weight="semibold">{item.day}</Text>
                <Text size="xl">{item.icon}</Text>
                <Text variant="bodySmall">
                  <span style={{ fontWeight: 600 }}>{item.high}°</span>
                  <span style={{ color: 'var(--ggui-color-neutral-500, #6b7280)', marginLeft: '4px' }}>{item.low}°</span>
                </Text>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}
